{
  "slots": [
    { "id": "arr", "type": "array", "label": "Sorted Array" }
  ],
  "inputs": [
    { "label": "Target", "default": "72" }
  ],
  "code": "class Playground {
    async run(inputs) {
        const target = parseInt(inputs.Target);
        const data = [2, 5, 8, 12, 16, 23, 38, 56, 72, 91];
        await this.arr.init(data);

        let low = 0;
        let high = data.length - 1;

        while (low <= high) {
            // Reset colors and highlight current active range
            this.arr.highlightRange(0, data.length - 1, '#1e293b'); // Dark blue-gray for inactive
            this.arr.highlightRange(low, high, '#3b82f6'); // Vibrant blue for active
            this.log(`Searching in range [${low}, ${high}]`);
            await this.await();

            let mid = Math.floor((low + high) / 2);
            this.arr.highlight(mid, '#f59e0b'); // Yellow for midpoint
            this.log(`Checking midpoint index ${mid} (Value: ${data[mid]})`);
            await this.await();

            if (data[mid] === target) {
                this.arr.highlight(mid, '#10b981'); // Green for success
                this.log(`MATCH! Target ${target} found at index ${mid}.`);
                return;
            } else if (data[mid] < target) {
                this.log(`${data[mid]} < ${target}. Discarding left half.`);
                low = mid + 1;
            } else {
                this.log(`${data[mid]} > ${target}. Discarding right half.`);
                high = mid - 1;
            }
            await this.await();
        }

        this.log('Target not found in the array.');
    }
}"
}

